export type Cell = [row: number, col: number];

const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;

const cellFromKey = (key: string): Cell => key.split(",").map(Number) as Cell;

const neighbors = (cell: Cell): Cell[] => {
  const [r, c] = cell;
  return [
    [r - 1, c - 1], [r - 1, c], [r - 1, c + 1],
    [r,     c - 1],             [r,     c + 1],
    [r + 1, c - 1], [r + 1, c], [r + 1, c + 1],
  ] as Cell[];
};

export function nextGeneration(cells: Cell[]): Cell[] {
  const liveSet = new Set(cells.map(cellKey));
  const neighborCount = new Map<string, number>();

  for (const cell of cells) {
    for (const n of neighbors(cell)) {
      const k = cellKey(n);
      neighborCount.set(k, (neighborCount.get(k) ?? 0) + 1);
    }
  }

  const result: Cell[] = [];
  for (const [k, count] of neighborCount) {
    const isAlive = liveSet.has(k);
    const survives = isAlive && count === 2;
    const isReborn = !isAlive && count === 3;
    if (survives || isReborn || count === 3 && isAlive) {
      result.push(cellFromKey(k));
    }
  }

  result.sort((a, b) => a[1] - b[1] || a[0] - b[0]);
  return result;
}

